- Data privacy: encryption (KMS), access logs, least privilege
- Reliability: idempotency, retries, error handling
- Cost: batching, thresholds, per-request pricing

## Code Example
```javascript
const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const comprehend = new AWS.Comprehend();
const dynamo = new AWS.DynamoDB.DocumentClient();

exports.handler = async (event) => {
  const rec = event.Records[0];
  const bucket = rec.s3.bucket.name;
  const key = decodeURIComponent(rec.s3.object.key.replace(/\+/g, ' '));
  const obj = await s3.getObject({Bucket: bucket, Key: key}).promise();
  const data = JSON.parse(obj.Body.toString('utf-8'));
  const text = data.text;
  const lang = data.language || 'en';

  const sentiment = (await comprehend.detectSentiment({Text: text, LanguageCode: lang}).promise()).Sentiment;
  const themes = (await comprehend.detectEntities({Text: text, LanguageCode: lang}).promise()).Entities.map(e => e.Type);

  await dynamo.put({
    TableName: 'FeedbackIndex',
    Item: {
      feedbackId: data.feedbackId,
      customerId: data.customerId,
      language: lang,
      sentiment,
      themes
    }
  }).promise();

  // Optionally write summary/output to S3 here
  return {status: 'ok'};
};
```

