## Complete AWS Pipeline Design

### Architecture Overview
1. **S3 Upload** → Triggers Lambda via S3 event notification
2. **Lambda** → Parses CSV, calls Comprehend batch APIs
3. **Comprehend** → Detects language, sentiment, key phrases
4. **Lambda** → Writes per-review JSON to S3, upserts DynamoDB index

### Lambda Implementation

```javascript
const { S3Client, PutObjectCommand, GetObjectCommand } = require('@aws-sdk/client-s3');
const { DynamoDBClient, PutItemCommand, GetItemCommand, UpdateItemCommand } = require('@aws-sdk/client-dynamodb');
const { ComprehendClient, BatchDetectDominantLanguageCommand, BatchDetectSentimentCommand, BatchDetectKeyPhrasesCommand } = require('@aws-sdk/client-comprehend');
const csv = require('csv-parser');
const { Readable } = require('stream');

const s3 = new S3Client({ region: process.env.AWS_REGION });
const ddb = new DynamoDBClient({ region: process.env.AWS_REGION });
const comprehend = new ComprehendClient({ region: process.env.AWS_REGION });

const BATCH_SIZE = 25; // Comprehend max batch size
const OUTPUT_BUCKET = process.env.OUTPUT_BUCKET;
const INDEX_TABLE = process.env.INDEX_TABLE;

exports.handler = async (event) => {
  const bucket = event.Records[0].s3.bucket.name;
  const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));

  try {
    // 1. Download and parse CSV
    const csvData = await downloadCSV(bucket, key);
    const reviews = await parseCSV(csvData);

    // 2. Process in batches of 25
    for (let i = 0; i < reviews.length; i += BATCH_SIZE) {
      const batch = reviews.slice(i, i + BATCH_SIZE);
      await processBatch(batch, bucket, key, i);
    }

    return { statusCode: 200, body: `Processed ${reviews.length} reviews` };
  } catch (error) {
    console.error('Error processing reviews:', error);
    throw error;
  }
};

async function downloadCSV(bucket, key) {
  const command = new GetObjectCommand({ Bucket: bucket, Key: key });
  const response = await s3.send(command);
  return streamToString(response.Body);
}

function streamToString(stream) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    stream.on('data', chunk => chunks.push(chunk));
    stream.on('error', reject);
    stream.on('end', () => resolve(Buffer.concat(chunks).toString('n')));
  });
}

async function parseCSV(csvString) {
  return new Promise((resolve, reject) => {
    const results = [];
    Readable.from(csvString)
      .pipe(csv())
      .on('data', data => results.push(data))
      .on('end', () => resolve(results))
      .on('error', reject);
  });
}

async function processBatch(batch, fileBucket, fileKey, batchIndex) {
  const texts = batch.map(r => r.reviewText || r.text || '');
  const reviewIds = batch.map(r => r.reviewId || r.id);

  // Detect language
  const langResult = await comprehend.send(
    new BatchDetectDominantLanguageCommand({ TextList: texts })
  );

  // Detect sentiment
  const sentimentResult = await comprehend.send(
    new BatchDetectSentimentCommand({ TextList: texts, LanguageCode: langResult.ResultList[0].Languages[0].LanguageCode })
  );

  // Detect key phrases
  const phrasesResult = await comprehend.send(
    new BatchDetectKeyPhrasesCommand({ TextList: texts, LanguageCode: langResult.ResultList[0].Languages[0].LanguageCode })
  );

  // Process results and write outputs
  for (let i = 0; i < batch.length; i++) {
    const reviewData = {
      reviewId: reviewIds[i],
      fileKey: fileKey,
      language: langResult.ResultList[i].Languages[0].LanguageCode,
      sentiment: sentimentResult.ResultList[i].Sentiment,
      sentimentScore: sentimentResult.ResultList[i].SentimentScore,
      keyPhrases: phrasesResult.ResultList[i].KeyPhrases.map(kp => kp.Text),
      keywordsKey: `${fileKey.replace('.csv', '')}/reviews/${reviewIds[i]}.json`,
      processedAt: new Date().toISOString()
    };

    // Write per-review JSON to S3
    await s3.send(new PutObjectCommand({
      Bucket: OUTPUT_BUCKET,
      Key: reviewData.keywordsKey,
      Body: JSON.stringify(reviewData),
      ContentType: 'application/json',
      ServerSideEncryption: 'AES256'
    }));

    // Upsert DynamoDB index (idempotent)
    await upsertDynamoDB(reviewData);
  }
}

async function upsertDynamoDB(reviewData) {
  const params = {
    TableName: INDEX_TABLE,
    Key: { reviewId: { S: reviewData.reviewId } },
    UpdateExpression: 'SET fileKey = :fk, language = :lang, #s = :sent, keywordsKey = :kk, processedAt = :pa, sentimentScore = :ss',
    ExpressionAttributeNames: { '#s': 'sentiment' },
    ExpressionAttributeValues: {
      ':fk': { S: reviewData.fileKey },
      ':lang': { S: reviewData.language },
      ':sent': { S: reviewData.sentiment },
      ':kk': { S: reviewData.keywordsKey },
      ':pa': { S: reviewData.processedAt },
      ':ss': { M: {
        positive: { N: reviewData.sentimentScore.Positive.toString() },
        negative: { N: reviewData.sentimentScore.Negative.toString() },
        neutral: { N: reviewData.sentimentScore.Neutral.toString() },
        mixed: { N: reviewData.sentimentScore.Mixed.toString() }
      }}
    }
  };

  await ddb.send(new UpdateItemCommand(params));
}
```

### IAM Role Policies (Least Privilege)

```json
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "s3:GetObject",
        "s3:PutObject"
      ],
      "Resource": [
        "arn:aws:s3:::input-bucket/*",
        "arn:aws:s3:::output-bucket/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": "s3:ListBucket",
      "Resource": "arn:aws:s3:::input-bucket"
    },
    {
      "Effect": "Allow",
      "Action": [
        "dynamodb:PutItem",
        "dynamodb:UpdateItem",
        "dynamodb:GetItem"
      ],
      "Resource": "arn:aws:dynamodb:region:account:table/reviews-index"
    },
    {
      "Effect": "Allow",
      "Action": [
        "comprehend:BatchDetectDominantLanguage",
        "comprehend:BatchDetectSentiment",
        "comprehend:BatchDetectKeyPhrases"
      ],
      "Resource": "*"
    },
    {
      "Effect": "Allow",
      "Action": "logs:CreateLogGroup",
      "Resource": "arn:aws:logs:region:account:*"
    },
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "arn:aws:logs:region:account:log-group:/aws/lambda/review-processor:*"
    }
  ]
}
```

### S3 Event Notification Configuration
```json
{
  "LambdaFunctionConfigurations": [
    {
      "LambdaFunctionArn": "arn:aws:lambda:region:account:function:review-processor",
      "Events": ["s3:ObjectCreated:Put"],
      "Filter": {
        "Key": {
          "FilterRules": [
            { "Name": "suffix", "Value": ".csv" }
          ]
        }
      }
    }
  ]
}
```

### Error Handling
- **Retry Logic**: Configure Lambda retry (3 attempts) with exponential backoff
- **Dead Letter Queue**: Set up DLQ for failed processing
- **Partial Batch Responses**: Use Lambda partial batch responses for SQS
- **Input Validation**: Validate CSV structure before processing
- **Graceful Degradation**: Handle individual row failures without crashing entire batch

### Encryption
- **S3**: Use SSE-KMS with CMK for both input/output buckets
- **DynamoDB**: Enable server-side encryption (default AWS managed)
- **In Transit**: Lambda uses HTTPS by default
- **Environment Variables**: Use AWS Secrets Manager for sensitive config

### Cost Considerations
- **Comprehend Batch APIs**: ~$0.0001 per 100 characters; batch of 25 is more cost-effective than 25 individual calls
- **S3**: Minimal for small files; enable lifecycle policies for JSON output
- **Lambda**: Free tier covers ~400K invocations/month; configure memory based on CSV size (recommend 512MB+ for 1MB files)
- **DynamoDB**: Use on-demand mode for unpredictable workloads, or provisioned for steady state
- **Optimization**: Process during off-peak hours if using provisioned capacity

