## Code Example
```javascript
const { ComprehendClient, DetectSentimentCommand, DetectDominantLanguageCommand, DetectKeyPhrasesCommand } = require('@aws-sdk/client-comprehend');
const { S3Client, PutObjectCommand } = require('@aws-sdk/client-s3');
const { DynamoDBClient, PutItemCommand } = require('@aws-sdk/client-dynamodb');

const comprehend = new ComprehendClient({ region: process.env.AWS_REGION });
const s3 = new S3Client({ region: process.env.AWS_REGION });
const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION });

exports.handler = async (event) => {
  const { messageId, content, timestamp } = JSON.parse(event.body);

  // Store raw message
  await s3.send(new PutObjectCommand({
    Bucket: process.env.RAW_BUCKET,
    Key: `${timestamp}/${messageId}.json`,
    Body: JSON.stringify({ messageId, content, timestamp }),
    ServerSideEncryption: 'AWS_KMS',
    KMSKeyId: process.env.KMS_KEY_ID
  }));

  // Language detection
  const langResult = await comprehend.send(new DetectDominantLanguageCommand({ Text: content }));
  const language = langResult.Languages[0].LanguageCode;

  // Sentiment analysis
  const sentimentResult = await comprehend.send(new DetectSentimentCommand({ Text: content, LanguageCode: language }));
  const sentiment = sentimentResult.Sentiment;

  // Key phrases extraction
  const phrasesResult = await comprehend.send(new DetectKeyPhrasesCommand({ Text: content, LanguageCode: language }));
  const topPhrases = phrasesResult.KeyPhrases.map(phrase => phrase.Text).slice(0, 5);

  // Store processed data
  await s3.send(new PutObjectCommand({
    Bucket: process.env.PROCESSED_BUCKET,
    Key: `${timestamp}/${messageId}.json`,
    Body: JSON.stringify({ messageId, language, sentiment, topPhrases, timestamp }),
    ServerSideEncryption: 'AWS_KMS',
    KMSKeyId: process.env.KMS_KEY_ID
  }));

  // Upsert DynamoDB
  await dynamodb.send(new PutItemCommand({
    TableName: process.env.DYNAMODB_TABLE,
    Item: {
      messageId: { S: messageId },
      language: { S: language },
      sentiment: { S: sentiment },
      topPhrases: { S: JSON.stringify(topPhrases) },
      timestamp: { N: timestamp.toString() }
    }
  }));

  return { statusCode: 200, body: JSON.stringify({ messageId, language, sentiment }) };
};
```

