// Example parsing of Textract response to extract a total amount
function extractTotal(textract) {
  const blocks = (textract?.Blocks || []).filter(b => b.BlockType === 'LINE');
  const totalLine = blocks.find(b => /total|amount/i.test(b.Text || ''));
  const amount = totalLine ? parseFloat(totalLine.Text.replace(/[^0-9.]/g, '')) : null;
  return amount;
}
