// Example Lambda snippet: update DynamoDB after MediaConvert completion
const AWS = require('aws-sdk');
const ddb = new AWS.DynamoDB.DocumentClient();

exports.handler = async (event) => {
  const { jobId, status, output } = event.detail;

  if (status === 'COMPLETE') {
    const params = {
      TableName: process.env.VIDEOS_TABLE,
      Item: {
        videoId: output.videoId,
        sourceKey: output.inputFile,
        thumbnailKey: output.thumbnailPath,
        previewKey: output.mp4Path,
        duration: output.duration,
        encodingQuality: '1080p',
        processedAt: new Date().toISOString()
      }
    };

    await ddb.put(params).promise();
  }
};
```

